</head>
<body>
    <h1>Personal Expense Tracker</h1>

    <div class="container">
        <h2>Add New Expense</h2>

        <div id="form-error" class="error-message"></div>

        <form id="expense-form">
            <div class="form-group">
                <div>
                    <label for="amount">Amount ($)</label>
                    <input type="number" id="amount" step="0.01" min="0.01" placeholder="Enter amount">
                </div>

                <div>
                    <label for="category">Category</label>
                    <select id="category">
                        <option value="">Select category</option>
                        <option value="groceries">Groceries</option>
                        <option value="transport">Transport</option>
                        <option value="bills">Bills</option>
                        <option value="fun">Fun</option>
                    </select>
                </div>

                <div>
                    <label for="date">Date</label>
                    <input type="date" id="date">
                </div>
            </div>

            <div class="form-group">
                <div style="flex: 2;">
                    <label for="note">Note (optional)</label>
                    <input type="text" id="note" placeholder="Enter a note (optional)">
                </div>

                <div style="display: flex; align-items: flex-end;">
                    <button type="submit" id="add-expense">Add Expense</button>
                </div>
            </div>
        </form>
    </div>

    <div class="container">
        <h2>Filters</h2>

        <div class="filters">
            <div class="filter-group">
                <label for="filter-category">Filter by Category</label>
                <select id="filter-category">
                    <option value="all">All Categories</option>
                    <option value="groceries">Groceries</option>
                    <option value="transport">Transport</option>
                    <option value="bills">Bills</option>
                    <option value="fun">Fun</option>
                </select>
            </div>

            <div class="filter-group">
                <label for="filter-from">From Date</label>
                <input type="date" id="filter-from">
            </div>

            <div class="filter-group">
                <label for="filter-to">To Date</label>
                <input type="date" id="filter-to">
            </div>
        </div>
    </div>

    <div class="container">
        <h2>Summary</h2>

        <div class="summary-section">
            <div class="total-display">Total: $<span id="total">0.00</span></div>

            <div class="category-totals" id="category-summary">
                <!-- Category totals will be populated here -->
            </div>
        </div>

        <h2>Expenses</h2>

        <ul id="expense-list" class="expense-list">
            <!-- Expenses will be added here -->
        </ul>
    </div>

    <script>
        // DOM Elements
        const expenseForm = document.getElementById('expense-form');
        const amountInput = document.getElementById('amount');
        const categorySelect = document.getElementById('category');
        const dateInput = document.getElementById('date');
        const noteInput = document.getElementById('note');
        const addExpenseBtn = document.getElementById('add-expense');
        const formError = document.getElementById('form-error');

        const filterCategory = document.getElementById('filter-category');
        const filterFrom = document.getElementById('filter-from');
        const filterTo = document.getElementById('filter-to');

        const expenseList = document.getElementById('expense-list');
        const totalDisplay = document.getElementById('total');
        const categorySummary = document.getElementById('category-summary');

        // State
        let expenses = [];

        // Constants
        const CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

        // Initialize
        function init() {
            loadExpenses();
            renderExpenses();
            setupEventListeners();

            // Set default date to today for new entries
            dateInput.valueAsDate = new Date();
        }

        // Load expenses from localStorage
        function loadExpenses() {
            const stored = localStorage.getItem('expenses');
            if (stored) {
                try {
                    expenses = JSON.parse(stored);
                } catch (e) {
                    console.error('Error parsing expenses:', e);
                    expenses = [];
                }
            }
        }

        // Save expenses to localStorage
        function saveExpenses() {
            localStorage.setItem('expenses', JSON.stringify(expenses));
        }

        // Validate form inputs
        function validateForm() {
            const amountValue = amountInput.value.trim();
            const categoryValue = categorySelect.value;
            const dateValue = dateInput.value;

            // Check if amount is empty, non-numeric, zero, or negative
            if (!amountValue) {
                return 'Please enter an amount.';
            }

            const amount = parseFloat(amountValue);
            if (isNaN(amount) || amount <= 0) {
                return 'Amount must be a positive number.';
            }

            // Check if category is selected
            if (!categoryValue) {
                return 'Please select a category.';
            }

            // Check if date is provided
            if (!dateValue) {
                return 'Please enter a date.';
            }

            return null; // No errors
        }

        // Show error message
        function showError(message) {
            formError.textContent = message;
            formError.style.display = 'block';
        }

        // Clear error message
        function clearError() {
            formError.textContent = '';
            formError.style.display = 'none';
        }

        // Format currency
        function formatCurrency(amount) {
            return amount.toFixed(2);
        }

        // Get filtered expenses based on current filters
        function getFilteredExpenses() {
            const categoryFilter = filterCategory.value;
            const fromFilter = filterFrom.value;
            const toFilter = filterTo.value;

            return expenses.filter(expense => {
                // Category filter
                if (categoryFilter !== 'all' && expense.category !== categoryFilter) {
                    return false;
                }

                // Date filters
                if (fromFilter || toFilter) {
                    const expenseDate = new Date(expense.date);

                    if (fromFilter) {
                        const fromDate = new Date(fromFilter);
                        if (expenseDate < fromDate) {
                            return false;
                        }
                    }

                    if (toFilter) {
                        const toDate = new Date(toFilter);
                        // Set to end of day for inclusive filtering
                        toDate.setHours(23, 59, 59, 999);
                        if (expenseDate > toDate) {
                            return false;
                        }
                    }
                }

                return true;
            });
        }

        // Calculate totals
        function calculateTotals(filteredExpenses) {
            const total = filteredExpenses.reduce((sum, expense) => sum + parseFloat(expense.amount), 0);

            const categoryTotals = {};
            CATEGORIES.forEach(cat => {
                categoryTotals[cat] = filteredExpenses
                    .filter(exp => exp.category === cat)
                    .reduce((sum, expense) => sum + parseFloat(expense.amount), 0);
            });

            return { total, categoryTotals };
        }

        // Render expenses list
        function renderExpenses() {
            const filtered = getFilteredExpenses();
            const { total, categoryTotals } = calculateTotals(filtered);

            // Update total display
            totalDisplay.textContent = formatCurrency(total);

            // Update category summary
            categorySummary.innerHTML = '';
            CATEGORIES.forEach(cat => {
                const catTotal = categoryTotals[cat];
                if (catTotal > 0) {
                    const catElement = document.createElement('div');
                    catElement.className = 'cat-total';
                    catElement.setAttribute('data-cat', cat);
                    catElement.textContent = `${cat.charAt(0).toUpperCase() + cat.slice(1)}: $${formatCurrency(catTotal)}`;
                    categorySummary.appendChild(catElement);
                }
            });

            // Render expense list
            expenseList.innerHTML = '';

            if (filtered.length === 0) {
                const noExpensesMsg = document.createElement('li');
                noExpensesMsg.className = 'no-expenses';
                noExpensesMsg.textContent = filtered.length === expenses.length 
                    ? 'No expenses recorded yet.' 
                    : 'No expenses match your filters.';
                expenseList.appendChild(noExpensesMsg);
                return;
            }

            // Sort by date descending (newest first)
            const sortedExpenses = [...filtered].sort((a, b) => new Date(b.date) - new Date(a.date));

            sortedExpenses.forEach(expense => {
                const li = document.createElement('li');
                li.className = 'expense';

                const expenseInfo = document.createElement('div');
                expenseInfo.className = 'expense-info';

                const amountSpan = document.createElement('span');
                amountSpan.className = 'expense-amount';
                amountSpan.textContent = `$${formatCurrency(parseFloat(expense.amount))}`;

                const detailsDiv = document.createElement('div');
                detailsDiv.className = 'expense-details';

                const categorySpan = document.createElement('span');
                categorySpan.textContent = expense.category.charAt(0).toUpperCase() + expense.category.slice(1);

                const dateSpan = document.createElement('span');
                dateSpan.textContent = new Date(expense.date).toLocaleDateString();

                detailsDiv.appendChild(categorySpan);
                if (expense.note) {
                    detailsDiv.appendChild(document.createTextNode(' • '));
                    detailsDiv.appendChild(document.createElement('br'));
                    detailsDiv.appendChild(document.createTextNode(expense.note));
                }
                detailsDiv.appendChild(document.createTextNode(' • '));
                detailsDiv.appendChild(dateSpan);

                expenseInfo.appendChild(amountSpan);
                expenseInfo.appendChild(detailsDiv);

                const deleteBtn = document.createElement('button');
                deleteBtn.className = 'exp-del';
                deleteBtn.textContent = 'Delete';
                deleteBtn.onclick = () => deleteExpense(expense.id);

                li.appendChild(expenseInfo);
                li.appendChild(deleteBtn);
                expenseList.appendChild(li);
            });
        }

        // Add new expense
        function addExpense(e) {
            e.preventDefault();

            const error = validateForm();
            if (error) {
                showError(error);
                return;
            }

            const expense = {
                id: Date.now().toString(),
                amount: parseFloat(amountInput.value).toFixed(2),
                category: categorySelect.value,
                date: dateInput.value,
                note: noteInput.value.trim()
            };

            expenses.push(expense);
            saveExpenses();

            // Clear form
            clearError();
            amountInput.value = '';
            categorySelect.value = '';
            noteInput.value = '';
            dateInput.valueAsDate = new Date();

            renderExpenses();
        }

        // Delete expense
        function deleteExpense(id) {
            expenses = expenses.filter(exp => exp.id !== id);
            saveExpenses();
            renderExpenses();
        }

        // Setup event listeners
        function setupEventListeners() {
            expenseForm.addEventListener('submit', addExpense);

            filterCategory.addEventListener('change', renderExpenses);
            filterFrom.addEventListener('change', renderExpenses);
            filterTo.addEventListener('change', renderExpenses);

            // Clear error when user starts typing in amount field
            amountInput.addEventListener('input', () => {
                if (formError.style.display === 'block') {
                    clearError();
                }
            });
        }

        // Initialize the app
        init();
    </script>
</body>
</html>
